queries.sparql:
PREFIX : <http://ambrosia.example.org/jobpostings#>
PREFIX p: <http://ambrosia.example.org/jobpostings/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?programname WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:programId ?cg . ?child a :Programs ; p:id ?cg . ?l p:graphicDesignerId ?pg . ?parent a :Graphic_Designers ; p:id ?pg . } GROUP BY ?child }
  ?child p:programName ?programname .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Graphic_Designers } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/jobpostings#>
PREFIX p: <http://ambrosia.example.org/jobpostings/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  distributive: { SELECT ?name ?programname WHERE {
  ?graphic_designers_programs a :Graphic_Designers_Programs .
  ?programs a :Programs .
  ?graphic_designers_programs p:hasPrograms ?programs .
  ?graphic_designers a :Graphic_Designers .
  ?graphic_designers_programs p:hasGraphic_Designers ?graphic_designers .
  ?graphic_designers p:name ?name .
  ?programs p:programName ?programname .
} }
  collective: { SELECT ?programname WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:programId ?cg . ?child a :Programs ; p:id ?cg . ?l p:graphicDesignerId ?pg . ?parent a :Graphic_Designers ; p:id ?pg . } GROUP BY ?child }
  ?child p:programName ?programname .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Graphic_Designers } }
  FILTER(?nf = ?total)
} }
}
